     1→#!/usr/bin/env node
     2→/**
     3→ * End-to-End Testing CLI Tool (T036k)
     4→ *
     5→ * Simple CLI for manual end-to-end testing of classification pipeline.
     6→ * Supports single email, batch, and date-range processing modes.
     7→ *
     8→ * Usage:
     9→ *   npm run test:pipeline -- --mode single --message-id <id>
    10→ *   npm run test:pipeline -- --mode batch --limit 10
    11→ *   npm run test:pipeline -- --mode date-range --start 2025-09-01 --end 2025-09-30 --limit 50
    12→ *   npm run test:pipeline -- --dry-run  # Classify without persisting
    13→ *
    14→ * Output:
    15→ *   - Per-email: [message_id] subject → labels: [label1, label2] (confidence: 0.85) - 8.3s
    16→ *   - Summary: Processed 10 emails in 83.5s (avg 8.35s/email), 9 success, 1 error
    17→ *   - Explainability traces: ./test-pipeline-results/<timestamp>/<message_id>.json
    18→ */
    19→
    20→import { promises as fs } from 'fs';
    21→import { join, dirname } from 'path';
    22→import {
    23→  fetchEmailById,
    24→  fetchUnclassifiedEmails,
    25→  fetchEmailsByDateRange,
    26→  closePool as closeQueryPool,
    27→} from '../persistence/email-query';
    28→import { saveClassificationResult, closePool as closeWriterPool } from '../persistence/classification-writer';
    29→import {
    30→  ClassificationPipeline,
    31→  ConfigurationLoader,
    32→  ClassificationPipelineError,
    33→  type CategoryConfiguration,
    34→  type EmailMessage,
    35→  type ClassificationResult,
    36→  type SelectedLabel,
    37→} from '@gmail-automation/classification-engine';
    38→import { ConsoleInterceptor } from './console-interceptor';
    39→
    40→/**
    41→ * CLI argument structure
    42→ */
    43→export interface CLIArguments {
    44→  mode: 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
    45→  messageId?: string;
    46→  limit?: number;
    47→  startDate?: string;
    48→  endDate?: string;
    49→  dryRun: boolean;
    50→  replayFrom?: string;
    51→  sessionId?: string;
    52→}
    53→
    54→/**
    55→ * Processing summary statistics
    56→ */
    57→export interface ProcessingSummary {
    58→  totalEmails: number;
    59→  success: number;
    60→  errors: number;
    61→  totalDurationMs: number;
    62→  errorDetails: Array<{ messageId: string; error: string }>;
    63→}
    64→
    65→/**
    66→ * Find the monorepo root directory by searching upward for package.json with workspaces
    67→ *
    68→ * @param startDir - Directory to start searching from (defaults to current working directory)
    69→ * @returns Path to monorepo root directory
    70→ * @throws Error if monorepo root cannot be found
    71→ */
    72→export async function findRepoRoot(startDir: string = process.cwd()): Promise<string> {
    73→  let currentDir = startDir;
    74→  const root = '/';
    75→
    76→  while (currentDir !== root) {
    77→    try {
    78→      const packageJsonPath = join(currentDir, 'package.json');
    79→      const packageJsonContent = await fs.readFile(packageJsonPath, 'utf-8');
    80→      const packageJson = JSON.parse(packageJsonContent);
    81→
    82→      // Check if this package.json has workspaces field (indicates monorepo root)
    83→      if (packageJson.workspaces) {
    84→        return currentDir;
    85→      }
    86→    } catch {
    87→      // package.json not found or not readable, continue searching
    88→    }
    89→
    90→    // Move up one directory
    91→    currentDir = dirname(currentDir);
    92→  }
    93→
    94→  throw new Error('Could not find monorepo root (package.json with workspaces field)');
    95→}
