    97→/**
    98→ * Display help message
    99→ */
   100→function displayHelp(): void {
   101→  console.log(`
   102→End-to-End Classification Pipeline Testing Tool
   103→
   104→Usage:
   105→  npm run test:pipeline -- --mode <mode> [options]
   106→
   107→Modes:
   108→  single       Process a single email by message ID
   109→  batch        Process multiple unclassified emails
   110→  date-range   Process emails within a date range
   111→  replay       Re-run full pipeline with session data (useful for configuration tuning)
   112→  replay-from  Replay pipeline from a specific stage using session data (advanced debugging)
   113→
   114→Options:
   115→  --mode <mode>           Required: single, batch, date-range, replay, or replay-from
   116→  --message-id <id>       Required for single mode: Gmail message ID
   117→  --limit <number>        Optional: Maximum emails to process (default: 10 for batch, 100 for date-range)
   118→  --start <YYYY-MM-DD>    Required for date-range: Start date
   119→  --end <YYYY-MM-DD>      Required for date-range: End date
   120→  --session-id <sessionId> Required for replay/replay-from modes: Session ID containing trace data
