   159→/**
   160→ * Parse command line arguments
   161→ *
   162→ * @param args - Process arguments (excluding node and script path)
   163→ * @returns Parsed CLI arguments
   164→ * @throws Error if required arguments missing or invalid
   165→ */
   166→export function parseArguments(args: string[]): CLIArguments {
   167→  // Check for help flag first
   168→  if (args.includes('--help') || args.includes('-h')) {
   169→    displayHelp();
   170→    process.exit(0);
   171→  }
   172→
   173→  const result: Partial<CLIArguments> = {
   174→    dryRun: false,
   175→  };
   176→
   177→  for (let i = 0; i < args.length; i++) {
   178→    const arg = args[i];
   179→
   180→    switch (arg) {
   181→      case '--mode':
   182→        if (i + 1 >= args.length) {
   183→          throw new Error('Missing value for --mode argument');
   184→        }
   185→        result.mode = args[++i] as 'single' | 'batch' | 'date-range' | 'replay' | 'replay-from';
   186→        break;
   187→      case '--message-id':
   188→        if (i + 1 >= args.length) {
   189→          throw new Error('Missing value for --message-id argument');
   190→        }
   191→        result.messageId = args[++i];
   192→        break;
   193→      case '--limit':
   194→        if (i + 1 >= args.length) {
   195→          throw new Error('Missing value for --limit argument');
   196→        }
   197→        result.limit = parseInt(args[++i], 10);
   198→        break;
   199→      case '--start':
   200→        if (i + 1 >= args.length) {
   201→          throw new Error('Missing value for --start argument');
   202→        }
   203→        result.startDate = args[++i];
   204→        break;
   205→      case '--end':
   206→        if (i + 1 >= args.length) {
   207→          throw new Error('Missing value for --end argument');
   208→        }
   209→        result.endDate = args[++i];
   210→        break;
   211→      case '--dry-run':
   212→        result.dryRun = true;
   213→        break;
   214→      case '--replay-from':
   215→        if (i + 1 >= args.length) {
   216→          throw new Error('Missing value for --replay-from argument');
   217→        }
   218→        result.replayFrom = args[++i];
   219→        break;
   220→      case '--session-id':
   221→        if (i + 1 >= args.length) {
   222→          throw new Error('Missing value for --session-id argument');
   223→        }
   224→        result.sessionId = args[++i];
   225→        break;
   226→    }
   227→  }
   228→
   229→  // Validate required arguments
   230→  if (!result.mode) {
   231→    throw new Error('Mode is required (--mode single|batch|date-range|replay|replay-from)');
   232→  }
   233→
   234→  if (!['single', 'batch', 'date-range', 'replay', 'replay-from'].includes(result.mode)) {
   235→    throw new Error('Invalid mode. Must be: single, batch, date-range, replay, or replay-from');
   236→  }
   237→
   238→  if (result.mode === 'single' && !result.messageId) {
   239→    throw new Error('message-id is required for single mode (--message-id <id>)');
   240→  }
   241→
   242→  if (result.mode === 'replay') {
   243→    if (!result.sessionId) {
   244→      throw new Error('--session-id <sessionId> is required for replay mode');
   245→    }
   246→  }
   247→
   248→  if (result.mode === 'replay-from') {
   249→    if (!result.replayFrom || !result.sessionId) {
   250→      throw new Error('Both --replay-from <stage> and --session-id <sessionId> are required for replay-from mode');
   251→    }
   252→  }
   253→
   254→  if (result.mode === 'date-range') {
   255→    if (!result.startDate || !result.endDate) {
   256→      throw new Error(
   257→        'Both start and end dates are required for date-range mode (--start YYYY-MM-DD --end YYYY-MM-DD)'
   258→      );
   259→    }
   260→  }
   261→
   262→  return result as CLIArguments;
   263→}
