   265→/**
   266→ * Load configuration from config directory
   267→ *
   268→ * @returns Loaded category configuration
   269→ * @throws Error if configuration loading fails
   270→ */
   271→async function loadConfiguration(): Promise<CategoryConfiguration> {
   272→  // Find monorepo root to locate config directory
   273→  const repoRoot = await findRepoRoot();
   274→
   275→  const configLoader = new ConfigurationLoader({
   276→    configDir: join(repoRoot, 'config'),
   277→    enableHotReload: false,
   278→    validateOnLoad: true,
   279→  });
   280→
   281→  const categoryConfigResult = await configLoader.loadCategoryConfiguration();
   282→
   283→  if (!categoryConfigResult.validationPassed) {
   284→    throw new Error(`Configuration validation failed:\n${categoryConfigResult.validationErrors.join('\n')}`);
   285→  }
   286→
   287→  // Validate config exists before type assertion
   288→  if (!categoryConfigResult.config) {
   289→    throw new Error('Configuration loading returned empty config');
   290→  }
   291→
   292→  // Return full CategoryConfiguration
   293→  // Use safe type assertion pattern as config loader returns runtime-validated configuration
   294→  const config = categoryConfigResult.config as unknown as CategoryConfiguration;
   295→  if (!config.processingConfig) {
   296→    throw new Error('Missing processingConfig in category configuration');
   297→  }
   298→
   299→  return config;
   300→}
