   302→/**
   303→ * Process single email through classification pipeline
   304→ *
   305→ * @param messageId - Gmail message ID
   306→ * @param config - Category configuration
   307→ * @param dryRun - If true, skip persistence
   308→ * @returns Processing summary
   309→ */
   310→export async function processSingleEmail(
   311→  messageId: string,
   312→  config: CategoryConfiguration,
   313→  dryRun: boolean
   314→): Promise<ProcessingSummary> {
   315→  const summary: ProcessingSummary = {
   316→    totalEmails: 1,
   317→    success: 0,
   318→    errors: 0,
   319→    totalDurationMs: 0,
   320→    errorDetails: [],
   321→  };
   322→
   323→  const startTime = Date.now();
   324→
   325→  // 1. Fetch email from database
   326→  console.log(`Fetching email: ${messageId}`);
   327→  const email = await fetchEmailById(messageId);
   328→
   329→  // 2. Initialize pipeline with test mode enabled
   330→  const pipeline = new ClassificationPipeline(config, true);
   331→
   332→  // 3. Create session directory for logging
   333→  const repoRoot = await findRepoRoot();
   334→  const tempSessionId = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5) + 'Z';
   335→  const sessionDir = join(repoRoot, 'test-pipeline-results', tempSessionId);
   336→  await fs.mkdir(sessionDir, { recursive: true });
   337→
   338→  // 4. Create console interceptor for this email
   339→  const logPath = join(sessionDir, `${email.id}.log`);
   340→  const interceptor = new ConsoleInterceptor(logPath);
   341→
   342→  try {
   343→    interceptor.start();
   344→
   345→    // 5. Classify email
   346→    console.log(`Classifying: [${email.id}] ${email.subject}`);
   347→    const result = await pipeline.classify(email);
   348→
   349→    // 6. Output result
   350→    console.log(formatEmailOutput(email, result));
   351→
   352→    // 7. Persist result (unless dry-run)
   353→    if (!dryRun) {
   354→      await saveClassificationResult(messageId, result);
   355→      console.log(`Persisted classification result for ${messageId}`);
   356→    } else {
   357→      console.log(`[DRY RUN] Skipped persistence for ${messageId}`);
   358→    }
   359→
   360→    // 8. Write explainability trace
   361→    const tracePath = await writeExplainabilityTrace(email, result.sessionId, result);
   362→    console.log(`Explainability trace: ${tracePath}`);
   363→
   364→    summary.success = 1;
   365→    summary.totalDurationMs = Date.now() - startTime;
   366→  } catch (error) {
   367→    summary.errors = 1;
   368→    summary.totalDurationMs = Date.now() - startTime;
   369→    summary.errorDetails.push({
   370→      messageId,
   371→      error: error instanceof Error ? error.message : String(error),
   372→    });
   373→
   374→    console.error(`Error processing ${messageId}: ${error instanceof Error ? error.message : String(error)}`);
   375→
   376→    // Write trace with error information and partial result (if available)
   377→    const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
   378→    await writeExplainabilityTrace(
   379→      email,
   380→      tempSessionId,
   381→      partialResult,
   382→      error instanceof Error ? error : new Error(String(error))
   383→    );
   384→  } finally {
   385→    // Always flush and close the interceptor
   386→    await interceptor.close();
   387→  }
   388→
   389→  return summary;
   390→}
