   392→/**
   393→ * Process batch of unclassified emails
   394→ *
   395→ * @param limit - Maximum number of emails to process
   396→ * @param config - Category configuration
   397→ * @param dryRun - If true, skip persistence
   398→ * @returns Processing summary
   399→ */
   400→export async function processBatchEmails(
   401→  limit: number,
   402→  config: CategoryConfiguration,
   403→  dryRun: boolean
   404→): Promise<ProcessingSummary> {
   405→  const summary: ProcessingSummary = {
   406→    totalEmails: 0,
   407→    success: 0,
   408→    errors: 0,
   409→    totalDurationMs: 0,
   410→    errorDetails: [],
   411→  };
   412→
   413→  const startTime = Date.now();
   414→
   415→  try {
   416→    // 1. Fetch unclassified emails
   417→    console.log(`Fetching up to ${limit} unclassified emails...`);
   418→    const emails = await fetchUnclassifiedEmails(limit);
   419→
   420→    summary.totalEmails = emails.length;
   421→    console.log(`Found ${emails.length} emails to process\n`);
   422→
   423→    if (emails.length === 0) {
   424→      console.log('No unclassified emails found.');
   425→      summary.totalDurationMs = Date.now() - startTime;
   426→      return summary;
   427→    }
   428→
   429→    // 2. Initialize pipeline with test mode enabled
   430→    const pipeline = new ClassificationPipeline(config, true);
   431→
   432→    // 3. Create single session for entire batch
   433→    const {
   434→      createClassificationSession,
   435→      incrementSessionSuccess,
   436→      incrementSessionError,
   437→      finalizeClassificationSession,
   438→    } = await import('@gmail-automation/classification-engine');
   439→    const session = createClassificationSession(config.processingConfig, 'sequential', emails.length, true);
   440→
   441→    // 4. Process each email with shared session
   442→    const repoRoot = await findRepoRoot();
   443→    const sessionDir = join(repoRoot, 'test-pipeline-results', session.id);
   444→    await fs.mkdir(sessionDir, { recursive: true });
   445→
   446→    for (let i = 0; i < emails.length; i++) {
   447→      const email = emails[i];
   448→
   449→      // Create console interceptor for this email
   450→      const logPath = join(sessionDir, `${email.id}.log`);
   451→      const interceptor = new ConsoleInterceptor(logPath);
   452→
   453→      try {
   454→        interceptor.start();
   455→        console.log(`Classifying [${email.id}] ${email.subject}`);
   456→        const result = await pipeline.classifyWithSession(email, session, i);
   457→
   458→        console.log(formatEmailOutput(email, result));
   459→
   460→        if (!dryRun) {
   461→          await saveClassificationResult(email.id, result);
   462→        }
   463→
   464→        await writeExplainabilityTrace(email, session.id, result);
   465→
   466→        incrementSessionSuccess(session);
   467→        summary.success++;
   468→      } catch (error) {
   469→        const errorMessage = error instanceof Error ? error.message : String(error);
   470→        const stageName = error instanceof ClassificationPipelineError ? error.stage : 'pipeline';
   471→        incrementSessionError(session, email.id, stageName, errorMessage, false);
   472→        summary.errors++;
   473→        summary.errorDetails.push({
   474→          messageId: email.id,
   475→          error: errorMessage,
   476→        });
   477→
   478→        console.error(`Error processing ${email.id}: ${errorMessage}`);
   479→
   480→        // Write trace with error information and partial result (if available)
   481→        const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
   482→        await writeExplainabilityTrace(
   483→          email,
   484→          session.id,
   485→          partialResult,
   486→          error instanceof Error ? error : new Error(String(error))
   487→        );
   488→      } finally {
   489→        // Always flush and close the interceptor
   490→        await interceptor.close();
   491→      }
   492→    }
   493→
   494→    // 5. Finalize session
   495→    finalizeClassificationSession(session);
   496→
   497→    summary.totalDurationMs = Date.now() - startTime;
   498→  } catch (error) {
   499→    console.error(`Fatal error in batch processing: ${error instanceof Error ? error.message : String(error)}`);
   500→    throw error;
   501→  }
   502→
   503→  return summary;
   504→}
