   570→    const session = createClassificationSession(config.processingConfig, 'sequential', emails.length, true);
   571→
   572→    // 4. Process each email with shared session
   573→    const repoRoot = await findRepoRoot();
   574→    const sessionDir = join(repoRoot, 'test-pipeline-results', session.id);
   575→    await fs.mkdir(sessionDir, { recursive: true });
   576→
   577→    for (let i = 0; i < emails.length; i++) {
   578→      const email = emails[i];
   579→
   580→      // Create console interceptor for this email
   581→      const logPath = join(sessionDir, `${email.id}.log`);
   582→      const interceptor = new ConsoleInterceptor(logPath);
   583→
   584→      try {
   585→        interceptor.start();
   586→        console.log(`Classifying [${email.id}] ${email.subject}`);
   587→        const result = await pipeline.classifyWithSession(email, session, i);
   588→
   589→        console.log(formatEmailOutput(email, result));
   590→
   591→        if (!dryRun) {
   592→          await saveClassificationResult(email.id, result);
   593→        }
   594→
   595→        await writeExplainabilityTrace(email, session.id, result);
   596→
   597→        incrementSessionSuccess(session);
   598→        summary.success++;
   599→      } catch (error) {
   600→        const errorMessage = error instanceof Error ? error.message : String(error);
   601→        const stageName = error instanceof ClassificationPipelineError ? error.stage : 'pipeline';
   602→        incrementSessionError(session, email.id, stageName, errorMessage, false);
   603→        summary.errors++;
   604→        summary.errorDetails.push({
   605→          messageId: email.id,
   606→          error: errorMessage,
   607→        });
   608→
   609→        console.error(`Error processing ${email.id}: ${errorMessage}`);
   610→
   611→        // Write trace with error information and partial result (if available)
   612→        const partialResult = error instanceof ClassificationPipelineError ? error.partialResult : undefined;
   613→        await writeExplainabilityTrace(
