   616→          partialResult,
   617→          error instanceof Error ? error : new Error(String(error))
   618→        );
   619→      } finally {
   620→        // Always flush and close the interceptor
   621→        await interceptor.close();
   622→      }
   623→    }
   624→
   625→    // 5. Finalize session
   626→    finalizeClassificationSession(session);
   627→
   628→    summary.totalDurationMs = Date.now() - startTime;
   629→  } catch (error) {
   630→    console.error(`Fatal error in date range processing: ${error instanceof Error ? error.message : String(error)}`);
   631→    throw error;
   632→  }
   633→
   634→  return summary;
   635→}
