   647→  const confidence = primaryLabel ? primaryLabel.confidence.toFixed(2) : '0.00';
   648→  const durationSec = (result.processingDurationMs / 1000).toFixed(1);
   649→
   650→  return `[${email.id}] ${email.subject} → labels: [${labels || 'none'}] (confidence: ${confidence}) - ${durationSec}s`;
