   789→
   790→      // Validate that we have enough stage data to replay from the requested stage
   791→      const stageIndex = STAGE_ORDER.indexOf(replayFromStage);
   792→      if (stageIndex === -1) {
   793→        throw new Error(`Invalid stage: ${replayFromStage}. Valid stages: ${STAGE_ORDER.join(', ')}`);
   794→      }
   795→
   796→      // Check that all prior stages have been executed (basic validation)
   797→      const explainabilityTrace = trace.classificationResult.explainabilityTrace;
   798→      const requiredStages = STAGE_ORDER.slice(0, stageIndex);
   799→
   800→      for (const stage of requiredStages) {
