     1→/**
     2→ * Action Determination Stage
     3→ *
     4→ * Stage 9 of the EmailCategorizer pipeline. Determines actions (archive, mark as read, custom)
     5→ * based on final labels, confidence scores, and action rules.
     6→ *
     7→ * This stage runs for ALL emails regardless of whether they went through AI classification:
     8→ * - For rule-based emails: Uses confidence from multi-label selection (stage 7)
     9→ * - For AI-classified emails: Uses confidence from AI classification (stage 8c)
    10→ *
    11→ * This stage is responsible for:
    12→ * - Evaluating archive thresholds based on confidence scores
    13→ * - Determining mark-as-read actions when archiving
    14→ * - Applying custom category-specific actions
    15→ * - Generating action reasoning for explainability
    16→ */
    17→
    18→import { z } from 'zod';
    19→import { EmailMessage, ClassificationSession } from '../types';
    20→import { ClassificationResult } from '../types/classification-result';
    21→import { validateEmailInput, validateSessionInput, validateConfigInput } from '../utils/validation';
    22→
    23→// Zod schema for action determination configuration
    24→export const ActionDeterminationConfigSchema = z.object({
    25→  archiveThresholds: z.object({
    26→    lowImportance: z.number().min(0).max(1),
    27→    mediumImportance: z.number().min(0).max(1),
    28→    highImportance: z.number().min(0).max(1),
    29→  }),
    30→  defaultArchiveThreshold: z.enum(['lowImportance', 'mediumImportance', 'highImportance']),
    31→  actionSettings: z
    32→    .object({
    33→      archiveIfBelowThreshold: z.boolean(),
    34→      markAsReadIfArchived: z.boolean(),
    35→      applyCustomActions: z.boolean(),
    36→    })
    37→    .optional(),
    38→  categoryActions: z.record(z.array(z.string())).optional(),
    39→});
    40→
    41→// Configuration interface for action determination
    42→export interface ActionDeterminationConfig {
    43→  archiveThresholds: {
    44→    lowImportance: number;
    45→    mediumImportance: number;
    46→    highImportance: number;
